-        // Dismiss when mouse leaves the real window
-        this._hoverLeaveId = actor.connect('leave-event', () => {
-            this.dismissHover();
-            return Clutter.EVENT_PROPAGATE;
+        // Poll pointer position — dismiss when mouse is outside both
+        // the stamp and the real window. Actor leave-event on
+        // MetaWindowActors is unreliable.
+        this._hoverPollId = GLib.timeout_add(GLib.PRIORITY_DEFAULT, 100, () => {
+            if (!this._hoverWindow)
+                return GLib.SOURCE_REMOVE;
+
+            const [mx, my] = global.get_pointer();
+            const fr = metaWindow.get_frame_rect();
+            const [sx, sy] = container.get_transformed_position();
+            const sw = container.width;
+            const sh = container.height;
+
+            const inWindow = mx >= fr.x && mx < fr.x + fr.width &&
+                             my >= fr.y && my < fr.y + fr.height;
+            const inStamp = mx >= sx && mx < sx + sw &&
+                            my >= sy && my < sy + sh;
+
+            if (!inWindow && !inStamp) {
+                this.dismissHover();
+                return GLib.SOURCE_REMOVE;
+            }
+            return GLib.SOURCE_CONTINUE;
         });
     }

